            "background": {
                "color": "#0b1f45"
            },
            "thumbnail": {
                "uri": "https://storage.googleapis.com/sovra_brand/Logo.png",
                "alt": "Your Logo Alt Text"
            }
        }
    },
    "protocol": "didcomm"
}

